import type { CareerQuestion } from "./pharmacy-tech-questions-extended";

export const pharmacyTechQuestionsBatch4: (CareerQuestion & { certification?: string })[] = [
  {"id":"ptcb-1256","stem":"A prescription reads: 'Metoprolol succinate 50 mg PO QD.' What is the brand name for this medication?","options":["Lopressor","Toprol-XL","Coreg","Bystolic"],"correctIndex":1,"rationale":"Metoprolol succinate is marketed as Toprol-XL (extended-release). Metoprolol tartrate is Lopressor (immediate-release, dosed BID). Coreg is carvedilol and Bystolic is nebivolol — both are different beta-blockers.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1257","stem":"Which suffix identifies angiotensin II receptor blockers (ARBs)?","options":["-pril","-sartan","-olol","-statin"],"correctIndex":1,"rationale":"ARBs end in -sartan (losartan, valsartan, irbesartan, olmesartan). ACE inhibitors end in -pril, beta-blockers in -olol, and HMG-CoA reductase inhibitors in -statin.","difficulty":1,"category":"Drug Classifications","topic":"drug suffixes","certification":"PTCB"},
  {"id":"ptcb-1258","stem":"A patient weighs 198 lbs. The prescribed dose is 15 mg/kg/day divided into 3 doses. What is the single dose in mg?","options":["450 mg","900 mg","1350 mg","2970 mg"],"correctIndex":0,"rationale":"Step 1: Convert weight: 198 lb ÷ 2.2 = 90 kg. Step 2: Daily dose: 15 mg/kg × 90 kg = 1350 mg/day. Step 3: Single dose: 1350 ÷ 3 = 450 mg per dose.","difficulty":3,"category":"Dosage Calculations","topic":"weight-based dosing","certification":"PTCB"},
  {"id":"ptcb-1259","stem":"What does the sig code 'ii gtts AU q4h' mean?","options":["Two drops in both ears every 4 hours","Two drops in the right ear every 4 hours","Two drops in both eyes every 4 hours","Two tablets by mouth every 4 hours"],"correctIndex":0,"rationale":"'ii' = two, 'gtts' = drops, 'AU' = auris utraque (both ears), 'q4h' = every 4 hours. AD = right ear, AS = left ear. OU = both eyes. Knowing these abbreviations prevents serious medication errors.","difficulty":2,"category":"Prescription Processing","topic":"sig codes","certification":"PTCB"},
  {"id":"ptcb-1260","stem":"Which pair of drugs is a critical look-alike/sound-alike (LASA) combination that has caused fatal errors?","options":["Atorvastatin and amlodipine","Vincristine and vinblastine","Metformin and metoprolol","Lisinopril and losartan"],"correctIndex":1,"rationale":"VinCRIStine and vinBLAStine are chemotherapy drugs with different dosing, routes, and toxicities. Errors between them have caused patient deaths. ISMP uses Tall Man Lettering to differentiate them. While the other pairs look similar, they have not caused the same level of fatal outcomes.","difficulty":3,"category":"Medication Safety","topic":"LASA drugs","certification":"PTCB"},
  {"id":"ptcb-1261","stem":"What is the brand name for escitalopram?","options":["Celexa","Lexapro","Zoloft","Prozac"],"correctIndex":1,"rationale":"Escitalopram is marketed as Lexapro, an SSRI used for depression and generalized anxiety disorder. Celexa is citalopram, Zoloft is sertraline, and Prozac is fluoxetine — all SSRIs but different drugs.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1262","stem":"An IV of 1000 mL NS is to infuse over 10 hours using a 20 gtt/mL set. What is the drip rate in gtt/min?","options":["17 gtt/min","25 gtt/min","33 gtt/min","50 gtt/min"],"correctIndex":2,"rationale":"Drip rate = (Volume × Drop factor) ÷ (Time in minutes) = (1000 mL × 20 gtt/mL) ÷ (600 min) = 20000 ÷ 600 = 33.3 ≈ 33 gtt/min.","difficulty":2,"category":"Dosage Calculations","topic":"IV flow rates","certification":"PTCB"},
  {"id":"ptcb-1263","stem":"A prescription reads: 'Prednisone 5 mg, #40, Sig: 2 tabs PO BID x 5d then 1 tab PO BID x 5d.' What is the day supply?","options":["5 days","10 days","15 days","20 days"],"correctIndex":1,"rationale":"Phase 1: 2 tabs BID × 5 days = 20 tabs. Phase 2: 1 tab BID × 5 days = 10 tabs. Total: 30 tabs over 10 days. Day supply = 10 days. The remaining 10 tablets are extra.","difficulty":2,"category":"Prescription Processing","topic":"day supply calculations","certification":"PTCB"},
  {"id":"ptcb-1264","stem":"Which of the following drug combinations increases the risk of serotonin syndrome?","options":["Lisinopril + hydrochlorothiazide","Sertraline + tramadol","Metformin + glipizide","Atorvastatin + ezetimibe"],"correctIndex":1,"rationale":"Sertraline (SSRI) combined with tramadol (which has serotonergic activity) increases the risk of serotonin syndrome — a potentially life-threatening condition causing agitation, hyperthermia, hyperreflexia, and clonus. Other serotonergic combinations include SSRIs with MAOIs or triptans.","difficulty":3,"category":"Drug Interactions","topic":"serotonin syndrome","certification":"PTCB"},
  {"id":"ptcb-1265","stem":"What is the generic name for Farxiga?","options":["Canagliflozin","Dapagliflozin","Empagliflozin","Ertugliflozin"],"correctIndex":1,"rationale":"Dapagliflozin is the generic name for Farxiga, an SGLT2 inhibitor used for type 2 diabetes, heart failure, and chronic kidney disease. Canagliflozin is Invokana, empagliflozin is Jardiance, and ertugliflozin is Steglatro.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1266","stem":"How many milliliters of a stock 10% povidone-iodine solution are needed to prepare 500 mL of a 2% solution?","options":["50 mL","100 mL","200 mL","250 mL"],"correctIndex":1,"rationale":"Using C1V1 = C2V2: 10% × V1 = 2% × 500 mL. V1 = (2 × 500) ÷ 10 = 100 mL of the 10% solution. Add sufficient diluent to reach 500 mL total volume.","difficulty":3,"category":"Dosage Calculations","topic":"dilution calculations","certification":"PTCB"},
  {"id":"ptcb-1267","stem":"A patient on warfarin has an INR of 5.2 (target 2-3). What is the most appropriate action for the pharmacy technician?","options":["Dispense the next warfarin refill as usual","Flag the result and notify the pharmacist immediately","Tell the patient to take extra warfarin","Recommend the patient take vitamin K supplements"],"correctIndex":1,"rationale":"An INR of 5.2 is supratherapeutic and puts the patient at high risk for bleeding. The pharmacy technician should immediately notify the pharmacist, who will contact the prescriber. Technicians should never give medical advice or adjust medications.","difficulty":2,"category":"Medication Safety","topic":"anticoagulant monitoring","certification":"PTCB"},
  {"id":"ptcb-1268","stem":"Which DEA form is used to report theft or loss of controlled substances?","options":["DEA Form 41","DEA Form 106","DEA Form 222","DEA Form 224"],"correctIndex":1,"rationale":"DEA Form 106 is used to report theft or significant loss of controlled substances. DEA Form 222 is for ordering Schedule II drugs. DEA Form 41 is for destruction of controlled substances. DEA Form 224 is for DEA registration.","difficulty":2,"category":"Regulations/Law","topic":"DEA forms","certification":"PTCB"},
  {"id":"ptcb-1269","stem":"What is the brand name for duloxetine?","options":["Effexor","Cymbalta","Pristiq","Savella"],"correctIndex":1,"rationale":"Duloxetine is marketed as Cymbalta, an SNRI used for depression, anxiety, diabetic neuropathy, fibromyalgia, and chronic musculoskeletal pain. Effexor is venlafaxine, Pristiq is desvenlafaxine, Savella is milnacipran — all SNRIs.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1270","stem":"A child weighing 33 lbs is prescribed amoxicillin 25 mg/kg/day divided TID. Available suspension: 250 mg/5 mL. What volume per dose?","options":["2.5 mL","5 mL","7.5 mL","10 mL"],"correctIndex":0,"rationale":"Step 1: Convert weight: 33 lb ÷ 2.2 = 15 kg. Step 2: Daily dose: 25 mg/kg × 15 kg = 375 mg/day. Step 3: Per dose: 375 ÷ 3 = 125 mg. Step 4: Volume: (125 mg × 5 mL) ÷ 250 mg = 2.5 mL per dose.","difficulty":3,"category":"Dosage Calculations","topic":"pediatric dosing","certification":"PTCB"},
  {"id":"ptcb-1271","stem":"Which medication requires REMS (Risk Evaluation and Mitigation Strategy) with iPLEDGE registration?","options":["Warfarin","Isotretinoin","Methotrexate","Clozapine"],"correctIndex":1,"rationale":"Isotretinoin (Accutane/Absorica) requires iPLEDGE REMS due to severe teratogenicity. Female patients must have negative pregnancy tests and use two forms of contraception. Clozapine has its own REMS (CRAS) for agranulocytosis monitoring.","difficulty":3,"category":"Medication Safety","topic":"REMS programs","certification":"PTCB"},
  {"id":"ptcb-1272","stem":"What is the sig interpretation for 'i tab SL PRN chest pain'?","options":["Take one tablet under the tongue as needed for chest pain","Take one tablet by mouth before meals for chest pain","Apply one patch to the chest as needed","Inhale one puff as needed for chest pain"],"correctIndex":0,"rationale":"SL = sublingual (under the tongue), PRN = as needed. This is a typical nitroglycerin sublingual tablet prescription. The patient places one tablet under the tongue when experiencing chest pain.","difficulty":1,"category":"Prescription Processing","topic":"sig codes","certification":"PTCB"},
  {"id":"ptcb-1273","stem":"Which of the following is contraindicated in a patient with a documented sulfa allergy?","options":["Amoxicillin","Ciprofloxacin","Sulfamethoxazole-trimethoprim","Azithromycin"],"correctIndex":2,"rationale":"Sulfamethoxazole-trimethoprim (Bactrim/Septra) is a sulfonamide antibiotic and is contraindicated in patients with sulfa allergies. Cross-reactivity can cause serious hypersensitivity reactions. Amoxicillin, ciprofloxacin, and azithromycin are not sulfonamides.","difficulty":2,"category":"Drug Interactions","topic":"drug allergies","certification":"PTCB"},
  {"id":"ptcb-1274","stem":"What is the generic name for Vraylar?","options":["Aripiprazole","Cariprazine","Brexpiprazole","Lumateperone"],"correctIndex":1,"rationale":"Cariprazine is the generic name for Vraylar, an atypical antipsychotic used for schizophrenia and bipolar disorder. Aripiprazole is Abilify, brexpiprazole is Rexulti, and lumateperone is Caplyta.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1275","stem":"A pharmacy receives an order for KCl 20 mEq in 1000 mL NS to infuse at 10 mEq/hr. What is the infusion rate in mL/hr?","options":["100 mL/hr","250 mL/hr","500 mL/hr","1000 mL/hr"],"correctIndex":2,"rationale":"Concentration: 20 mEq/1000 mL = 0.02 mEq/mL. Rate: 10 mEq/hr ÷ 0.02 mEq/mL = 500 mL/hr. Potassium chloride is a high-alert medication; the infusion rate must be carefully verified to prevent cardiac toxicity.","difficulty":3,"category":"Dosage Calculations","topic":"electrolyte calculations","certification":"PTCB"},
  {"id":"ptcb-1276","stem":"What does DAW 2 indicate on a prescription?","options":["Prescriber requires brand only","Patient requested brand product","Pharmacist selected brand product","Generic not in stock"],"correctIndex":1,"rationale":"DAW 2 means the patient (not the prescriber) requested the brand-name product. DAW 1 means the prescriber requires brand. DAW 3 means the pharmacist selected brand. DAW 4 means generic is not in stock.","difficulty":1,"category":"Prescription Processing","topic":"DAW codes","certification":"PTCB"},
  {"id":"ptcb-1277","stem":"Which error-prone abbreviation should never be used according to ISMP?","options":["BID","PO","QD","TID"],"correctIndex":2,"rationale":"ISMP includes 'QD' (daily) on its 'Do Not Use' list because it can be mistaken for 'QID' (four times daily) or 'QOD' (every other day). Write 'daily' instead. BID, PO, and TID are generally acceptable abbreviations.","difficulty":2,"category":"Medication Safety","topic":"error-prone abbreviations","certification":"PTCB"},
  {"id":"ptcb-1278","stem":"What is the generic name for Otezla?","options":["Tofacitinib","Apremilast","Upadacitinib","Baricitinib"],"correctIndex":1,"rationale":"Apremilast is the generic name for Otezla, a PDE4 inhibitor used for psoriatic arthritis and plaque psoriasis. Tofacitinib is Xeljanz (JAK inhibitor), upadacitinib is Rinvoq, and baricitinib is Olumiant.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1279","stem":"A patient needs 500 mL of 0.45% NaCl. How many grams of NaCl are required?","options":["0.45 g","2.25 g","4.5 g","22.5 g"],"correctIndex":1,"rationale":"0.45% w/v means 0.45 g per 100 mL. For 500 mL: (0.45 g/100 mL) × 500 mL = 2.25 g of NaCl needed.","difficulty":2,"category":"Dosage Calculations","topic":"percent concentration","certification":"PTCB"},
  {"id":"ptcb-1280","stem":"A patient taking lithium should avoid which OTC medication class due to increased lithium toxicity risk?","options":["Antihistamines","Proton pump inhibitors","NSAIDs","Antacids"],"correctIndex":2,"rationale":"NSAIDs (ibuprofen, naproxen) decrease renal lithium clearance, leading to increased lithium levels and potential toxicity. Symptoms of lithium toxicity include tremor, confusion, and seizures. Patients on lithium should use acetaminophen for pain instead.","difficulty":3,"category":"Drug Interactions","topic":"lithium interactions","certification":"PTCB"},
  {"id":"ptcb-1281","stem":"What is the generic name for Trelegy Ellipta?","options":["Budesonide/formoterol/glycopyrrolate","Fluticasone/umeclidinium/vilanterol","Beclomethasone/formoterol/glycopyrrolate","Mometasone/indacaterol/glycopyrrolate"],"correctIndex":1,"rationale":"Trelegy Ellipta contains fluticasone furoate/umeclidinium/vilanterol — an ICS/LAMA/LABA triple therapy inhaler for COPD maintenance. It combines an inhaled corticosteroid, long-acting muscarinic antagonist, and long-acting beta-2 agonist.","difficulty":3,"category":"Pharmacology","topic":"respiratory medications","certification":"PTCB"},
  {"id":"ptcb-1282","stem":"A prescription for eye drops reads: 'ii gtts OS TID.' Which eye should receive the drops?","options":["Right eye only","Left eye only","Both eyes","Neither — OS is not a valid abbreviation"],"correctIndex":1,"rationale":"OS = oculus sinister (left eye). OD = oculus dexter (right eye). OU = oculus uterque (both eyes). The patient should instill 2 drops in the left eye three times daily.","difficulty":1,"category":"Prescription Processing","topic":"sig codes","certification":"PTCB"},
  {"id":"ptcb-1283","stem":"Which medication has a boxed warning for Clostridioides difficile-associated diarrhea (CDAD)?","options":["Amoxicillin","Clindamycin","Azithromycin","Cephalexin"],"correctIndex":1,"rationale":"Clindamycin carries a boxed warning for CDAD (C. diff colitis). While all antibiotics can cause CDAD, clindamycin has the highest risk. Symptoms include watery diarrhea, fever, and abdominal pain. Treatment is oral vancomycin or fidaxomicin.","difficulty":3,"category":"Medication Safety","topic":"boxed warnings","certification":"PTCB"},
  {"id":"ptcb-1284","stem":"What is the purpose of the National Drug Code (NDC)?","options":["Identify the prescriber","Track controlled substance dispensing","Uniquely identify a drug product","Verify insurance coverage"],"correctIndex":2,"rationale":"The NDC is a unique 10-digit identifier for drug products in the US. It contains three segments: labeler code (manufacturer), product code (drug, strength, dosage form), and package code (package size). It is used for billing, inventory, and product identification.","difficulty":1,"category":"Prescription Processing","topic":"NDC numbers","certification":"PTCB"},
  {"id":"ptcb-1285","stem":"What is the brand name for sacubitril/valsartan?","options":["Entresto","Diovan","Corlanor","Verquvo"],"correctIndex":0,"rationale":"Entresto is the brand name for sacubitril/valsartan, an ARNI (angiotensin receptor-neprilysin inhibitor) used for heart failure with reduced ejection fraction. Diovan is valsartan alone, Corlanor is ivabradine, and Verquvo is vericiguat.","difficulty":2,"category":"Pharmacology","topic":"cardiac medications","certification":"PTCB"},
  {"id":"ptcb-1286","stem":"You need to prepare 500 mL of a 1:200 solution from a 1:50 stock solution. How many mL of stock are needed?","options":["62.5 mL","125 mL","250 mL","375 mL"],"correctIndex":1,"rationale":"1:200 = 0.5%. 1:50 = 2%. Using C1V1 = C2V2: 2% × V1 = 0.5% × 500 mL. V1 = 250 ÷ 2 = 125 mL of stock solution. Add 375 mL diluent to reach 500 mL total.","difficulty":4,"category":"Dosage Calculations","topic":"dilution calculations","certification":"PTCB"},
  {"id":"ptcb-1287","stem":"Which high-alert medication requires independent double-verification before administration in most hospitals?","options":["Acetaminophen","Amoxicillin","Insulin","Cetirizine"],"correctIndex":2,"rationale":"Insulin is an ISMP high-alert medication requiring independent double-verification of the dose, concentration, and rate before administration. Insulin errors (wrong type, wrong dose, wrong patient) are among the most common and harmful medication errors in hospitals.","difficulty":2,"category":"Medication Safety","topic":"high-alert medications","certification":"PTCB"},
  {"id":"ptcb-1288","stem":"What is the generic name for Verquvo?","options":["Ivabradine","Vericiguat","Dapagliflozin","Sacubitril"],"correctIndex":1,"rationale":"Vericiguat is the generic name for Verquvo, a soluble guanylate cyclase (sGC) stimulator used for chronic heart failure after a recent hospitalization. Ivabradine is Corlanor, dapagliflozin is Farxiga, and sacubitril is part of Entresto.","difficulty":3,"category":"Pharmacology","topic":"cardiac medications","certification":"PTCB"},
  {"id":"ptcb-1289","stem":"A prescription calls for 30 capsules of a compounded medication. Each capsule should contain 250 mg of active ingredient. The active ingredient has a purity of 80%. How many mg of powder should be weighed for the entire batch?","options":["7,500 mg","9,375 mg","6,000 mg","10,000 mg"],"correctIndex":1,"rationale":"Total drug needed: 250 mg × 30 capsules = 7,500 mg pure drug. Since the powder is 80% pure: 7,500 ÷ 0.80 = 9,375 mg of powder needed to get 7,500 mg of actual active ingredient.","difficulty":4,"category":"Compounding","topic":"purity calculations","certification":"PTCB"},
  {"id":"ptcb-1290","stem":"Which of the following foods significantly interacts with MAO inhibitors?","options":["Bananas","Aged cheese","White rice","Fresh chicken"],"correctIndex":1,"rationale":"Aged cheese contains high levels of tyramine, which can cause a hypertensive crisis in patients taking MAO inhibitors. Other tyramine-rich foods include aged meats, fermented foods, red wine, and soy sauce. This is potentially fatal.","difficulty":3,"category":"Drug Interactions","topic":"food-drug interactions","certification":"PTCB"},
  {"id":"ptcb-1291","stem":"A prescription reads: 'Fluticasone/salmeterol 250/50, 1 puff INH BID.' What is the brand name?","options":["Symbicort","Advair","Breo Ellipta","Dulera"],"correctIndex":1,"rationale":"Advair (Diskus or HFA) contains fluticasone/salmeterol. Symbicort is budesonide/formoterol, Breo Ellipta is fluticasone/vilanterol, and Dulera is mometasone/formoterol. All are ICS/LABA combinations for asthma/COPD.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1292","stem":"A pharmacy technician notices that two medications on a shelf have similar packaging. What is the best action to reduce dispensing errors?","options":["Move one medication to a different shelf location","Continue as usual since both are clearly labeled","Remove one medication from inventory","Alert the pharmacist only if an error occurs"],"correctIndex":0,"rationale":"Separating look-alike medications on different shelves is a proactive ISMP-recommended safety measure. Physical separation, tall-man lettering, and shelf alerts all reduce the chance of selecting the wrong product.","difficulty":1,"category":"Medication Safety","topic":"error prevention","certification":"PTCB"},
  {"id":"ptcb-1293","stem":"How many teaspoons are in 1 tablespoon?","options":["2 tsp","3 tsp","4 tsp","5 tsp"],"correctIndex":1,"rationale":"1 tablespoon = 3 teaspoons = 15 mL. 1 teaspoon = 5 mL. This is a fundamental household conversion frequently tested on pharmacy certification exams.","difficulty":1,"category":"Dosage Calculations","topic":"household conversions","certification":"PTCB"},
  {"id":"ptcb-1294","stem":"Which Schedule II drug requires DEA Form 222 for ordering?","options":["Alprazolam","Tramadol","Oxycodone","Codeine with APAP"],"correctIndex":2,"rationale":"Oxycodone is a Schedule II controlled substance that requires DEA Form 222 (or CSOS electronic ordering) for procurement. Alprazolam and tramadol are C-IV, and codeine with APAP is C-III. Only C-II substances require Form 222.","difficulty":2,"category":"Regulations/Law","topic":"DEA ordering","certification":"PTCB"},
  {"id":"ptcb-1295","stem":"What is the generic name for Keytruda?","options":["Nivolumab","Pembrolizumab","Atezolizumab","Ipilimumab"],"correctIndex":1,"rationale":"Pembrolizumab is the generic name for Keytruda, a PD-1 immune checkpoint inhibitor used for various cancers. Nivolumab is Opdivo, atezolizumab is Tecentriq, and ipilimumab is Yervoy. These are immunotherapy agents.","difficulty":3,"category":"Pharmacology","topic":"oncology medications","certification":"PTCB"},
  {"id":"ptcb-1296","stem":"An IV bag of 250 mL is to infuse over 2 hours. The tubing delivers 60 gtt/mL (microdrip). What is the drip rate?","options":["62.5 gtt/min","125 gtt/min","250 gtt/min","500 gtt/min"],"correctIndex":1,"rationale":"Drip rate = (Volume × Drop factor) ÷ (Time in min) = (250 × 60) ÷ 120 = 15000 ÷ 120 = 125 gtt/min. With microdrip (60 gtt/mL) tubing, the gtt/min equals the mL/hr.","difficulty":2,"category":"Dosage Calculations","topic":"IV flow rates","certification":"PTCB"},
  {"id":"ptcb-1297","stem":"A patient presents a prescription dated 45 days ago for hydrocodone/APAP. Can it be filled?","options":["Yes, it has no expiration","No, C-II prescriptions expire after 30 days","It depends on state law, but federally there is no expiration for C-II","Yes, Schedule III drugs are valid for 6 months"],"correctIndex":2,"rationale":"There is no federal expiration date for Schedule II prescriptions. However, many states impose their own limits (commonly 30, 60, or 90 days). The pharmacist must verify state-specific regulations. Hydrocodone combinations are C-II.","difficulty":3,"category":"Regulations/Law","topic":"controlled substance prescriptions","certification":"PTCB"},
  {"id":"ptcb-1298","stem":"Which medication should be dispensed with an oral syringe rather than a household teaspoon for pediatric patients?","options":["Chewable amoxicillin tablets","Liquid acetaminophen","Cetirizine tablets","Omeprazole capsules"],"correctIndex":1,"rationale":"Liquid medications for pediatric patients should be dispensed with an oral syringe or calibrated measuring device, not household teaspoons, which can vary in volume and lead to dosing errors. This is an FDA and ISMP recommendation for patient safety.","difficulty":2,"category":"Medication Safety","topic":"pediatric safety","certification":"PTCB"},
  {"id":"ptcb-1299","stem":"What is the brand name for montelukast?","options":["Flovent","Singulair","Spiriva","Atrovent"],"correctIndex":1,"rationale":"Montelukast is Singulair, a leukotriene receptor antagonist used for asthma and allergic rhinitis. Flovent is fluticasone inhaler (ICS), Spiriva is tiotropium (LAMA), and Atrovent is ipratropium (SAMA).","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1300","stem":"What is the alligation alternate result when mixing 20% and 5% solutions to make a 12% solution?","options":["7 parts of 20% and 8 parts of 5%","8 parts of 20% and 7 parts of 5%","12 parts of 20% and 3 parts of 5%","5 parts of 20% and 20 parts of 5%"],"correctIndex":0,"rationale":"Alligation: 20% gives (12-5) = 7 parts. 5% gives (20-12) = 8 parts. So mix 7 parts of the 20% solution with 8 parts of the 5% solution to obtain a 12% final concentration.","difficulty":3,"category":"Dosage Calculations","topic":"alligation","certification":"PTCB"},
  {"id":"ptcb-1301","stem":"Methotrexate is sometimes accidentally taken daily instead of weekly. What type of error is this?","options":["Wrong drug error","Wrong dose frequency error","Wrong route error","Wrong patient error"],"correctIndex":1,"rationale":"Methotrexate for rheumatoid arthritis or psoriasis is dosed WEEKLY, not daily. Daily dosing is a well-known, potentially fatal error. ISMP recommends clearly labeling methotrexate prescriptions with the specific day of the week for dosing.","difficulty":3,"category":"Medication Safety","topic":"high-alert medication errors","certification":"PTCB"},
  {"id":"ptcb-1302","stem":"What is the generic name for Skyrizi?","options":["Secukinumab","Risankizumab","Guselkumab","Ixekizumab"],"correctIndex":1,"rationale":"Risankizumab is the generic name for Skyrizi, an IL-23 inhibitor biologic used for plaque psoriasis and psoriatic arthritis. Secukinumab is Cosentyx, guselkumab is Tremfya, and ixekizumab is Taltz.","difficulty":3,"category":"Pharmacology","topic":"biologic medications","certification":"PTCB"},
  {"id":"ptcb-1303","stem":"A pharmacy technician notices a prescription for warfarin 5 mg and fluconazole 200 mg for the same patient. What should they do?","options":["Fill both prescriptions without comment","Alert the pharmacist about potential drug interaction","Call the patient to ask about their medications","Refuse to fill the fluconazole prescription"],"correctIndex":1,"rationale":"Fluconazole is a strong CYP2C9 inhibitor that significantly increases warfarin levels, raising bleeding risk. The technician should alert the pharmacist for interaction review. Technicians should never refuse to fill or make clinical decisions independently.","difficulty":2,"category":"Drug Interactions","topic":"CYP450 interactions","certification":"PTCB"},
  {"id":"ptcb-1304","stem":"A prescription reads: 'Insulin glargine 100 units/mL, inject 32 units SubQ QHS, Disp: 1 vial (10 mL).' What is the day supply?","options":["10 days","15 days","31 days","100 days"],"correctIndex":2,"rationale":"Total units in vial: 100 units/mL × 10 mL = 1000 units. Daily use: 32 units. Day supply: 1000 ÷ 32 = 31.25, rounded to 31 days. Insurance typically accepts 31 days for a 10 mL insulin vial at this dose.","difficulty":2,"category":"Dosage Calculations","topic":"insulin day supply","certification":"PTCB"},
  {"id":"ptcb-1305","stem":"Which controlled substance reporting system tracks prescription dispensing to identify potential abuse?","options":["MedWatch","VAERS","PDMP (Prescription Drug Monitoring Program)","REMS"],"correctIndex":2,"rationale":"PDMPs (Prescription Drug Monitoring Programs) are state-run databases that track dispensing of controlled substances. They help identify doctor shopping, over-prescribing, and potential diversion. Most states require pharmacists to check the PDMP before dispensing controlled substances.","difficulty":2,"category":"Regulations/Law","topic":"PDMP","certification":"PTCB"},
  {"id":"ptcb-1306","stem":"What is the brand name for bupropion XL?","options":["Wellbutrin XL","Effexor XR","Cymbalta","Trintellix"],"correctIndex":0,"rationale":"Bupropion XL is marketed as Wellbutrin XL (for depression) and also as Zyban (for smoking cessation). It is an NDRI (norepinephrine-dopamine reuptake inhibitor). Effexor is venlafaxine, Cymbalta is duloxetine, Trintellix is vortioxetine.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1307","stem":"When reconstituting an antibiotic powder for oral suspension, which step is most critical?","options":["Use hot water for faster dissolution","Add all diluent at once and shake vigorously","Tap the bottle to loosen powder, then add the correct amount of purified water in two portions","Add juice to improve taste"],"correctIndex":2,"rationale":"Proper reconstitution requires tapping the bottle to loosen packed powder, then adding purified water (not tap water, juice, or hot water) in two portions, shaking after each addition to ensure complete dissolution and correct final volume.","difficulty":2,"category":"Compounding","topic":"reconstitution","certification":"PTCB"},
  {"id":"ptcb-1308","stem":"Which benzodiazepine has the shortest half-life?","options":["Diazepam","Clonazepam","Triazolam","Chlordiazepoxide"],"correctIndex":2,"rationale":"Triazolam (Halcion) has the shortest half-life (1.5-5.5 hours) among common benzodiazepines. Diazepam (Valium) has the longest (20-100 hours including active metabolites). Clonazepam has a half-life of 18-50 hours.","difficulty":3,"category":"Pharmacology","topic":"drug pharmacokinetics","certification":"PTCB"},
  {"id":"ptcb-1309","stem":"A prescription reads: 'Amoxicillin 500 mg, #30, i cap PO TID × 10 days, 0 refills.' The patient asks for a refill 5 days later. What should the technician do?","options":["Process the refill since the patient needs more","Inform the patient that no refills are authorized and contact the prescriber","Give the patient a partial fill","Transfer the prescription to another pharmacy"],"correctIndex":1,"rationale":"The prescription has zero refills. The technician should inform the patient and offer to contact the prescriber for authorization. Technicians cannot authorize refills or override zero-refill prescriptions.","difficulty":1,"category":"Prescription Processing","topic":"refill management","certification":"PTCB"},
  {"id":"ptcb-1310","stem":"What temperature range defines refrigerated storage for pharmaceuticals?","options":["0-2°C (32-36°F)","2-8°C (36-46°F)","8-15°C (46-59°F)","15-25°C (59-77°F)"],"correctIndex":1,"rationale":"Refrigerated pharmaceutical storage is 2-8°C (36-46°F). Freezing (below 0°C) can damage many medications including insulin and vaccines. Room temperature is 20-25°C. These storage ranges are defined by USP.","difficulty":1,"category":"Inventory Management","topic":"storage temperatures","certification":"PTCB"},
  {"id":"ptcb-1311","stem":"What is the generic name for Rinvoq?","options":["Tofacitinib","Upadacitinib","Baricitinib","Abrocitinib"],"correctIndex":1,"rationale":"Upadacitinib is the generic name for Rinvoq, a JAK inhibitor used for rheumatoid arthritis, psoriatic arthritis, ulcerative colitis, and atopic dermatitis. Tofacitinib is Xeljanz, baricitinib is Olumiant, and abrocitinib is Cibinqo.","difficulty":2,"category":"Pharmacology","topic":"immunosuppressant medications","certification":"PTCB"},
  {"id":"ptcb-1312","stem":"How many mg of NaCl are in 1 liter of 0.9% Normal Saline?","options":["0.9 mg","9 mg","900 mg","9000 mg"],"correctIndex":3,"rationale":"0.9% = 0.9 g per 100 mL. In 1000 mL: 0.9 × 10 = 9 g = 9000 mg of NaCl. Normal saline is an isotonic solution commonly used for IV hydration and medication dilution.","difficulty":2,"category":"Dosage Calculations","topic":"IV solution calculations","certification":"PTCB"},
  {"id":"ptcb-1313","stem":"Which drug requires a serum trough level to be drawn just before the next dose?","options":["Amoxicillin","Vancomycin","Metformin","Atorvastatin"],"correctIndex":1,"rationale":"Vancomycin requires therapeutic drug monitoring with trough levels drawn 30 minutes before the next dose. Target AUC/MIC-guided dosing is now preferred. Trough levels help prevent nephrotoxicity and ototoxicity while ensuring efficacy.","difficulty":3,"category":"Medication Safety","topic":"therapeutic drug monitoring","certification":"PTCB"},
  {"id":"ptcb-1314","stem":"A patient asks the technician if they can crush their Toprol-XL tablets. What is the correct response?","options":["Yes, all tablets can be crushed","No, extended-release tablets should not be crushed","Yes, but only if mixed with applesauce","Ask the patient to try splitting them instead"],"correctIndex":1,"rationale":"Extended-release (XL/XR/ER/CR) tablets should never be crushed, as this destroys the extended-release mechanism and can release the entire dose at once, potentially causing toxicity. The technician should refer the patient to the pharmacist for alternatives.","difficulty":1,"category":"Medication Safety","topic":"do not crush","certification":"PTCB"},
  {"id":"ptcb-1315","stem":"What is the brand name for tamsulosin?","options":["Cardura","Flomax","Hytrin","Rapaflo"],"correctIndex":1,"rationale":"Tamsulosin is marketed as Flomax, an alpha-1 blocker used for benign prostatic hyperplasia (BPH). Cardura is doxazosin, Hytrin is terazosin (both alpha blockers), and Rapaflo is silodosin.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1316","stem":"A patient brings in a prescription for amoxicillin written by a dentist. Can the pharmacy fill it?","options":["No, only physicians can write prescriptions","No, dentists can only prescribe controlled substances","Yes, dentists are authorized prescribers within their scope of practice","Only if the pharmacy calls to verify"],"correctIndex":2,"rationale":"Dentists are authorized prescribers who can write prescriptions for medications within their scope of practice, including antibiotics (amoxicillin for dental infections), pain medications, and local anesthetics. Verification is only needed if there are concerns about the prescription's validity.","difficulty":1,"category":"Regulations/Law","topic":"prescriptive authority","certification":"PTCB"},
  {"id":"ptcb-1317","stem":"What is the correct ratio for preparing a 1:1000 epinephrine solution?","options":["1 g in 100 mL","1 g in 1000 mL","1 mg in 1000 mL","0.1 g in 100 mL"],"correctIndex":1,"rationale":"A 1:1000 ratio strength means 1 g of solute in 1000 mL of solution. This equals 1 mg/mL. Epinephrine 1:1000 (1 mg/mL) is used for IM injection in anaphylaxis. Epinephrine 1:10,000 (0.1 mg/mL) is used for IV administration in cardiac arrest.","difficulty":3,"category":"Dosage Calculations","topic":"ratio strength","certification":"PTCB"},
  {"id":"ptcb-1318","stem":"Which of the following is NOT a required element on a prescription label?","options":["Patient name","Prescriber's DEA number","Pharmacy name and address","Directions for use"],"correctIndex":1,"rationale":"The prescriber's DEA number appears on the prescription form (for controlled substances) but is NOT required on the prescription label. Required label elements include: pharmacy name/address, patient name, drug name/strength, directions, date filled, prescription number, and refill information.","difficulty":2,"category":"Prescription Processing","topic":"prescription labeling","certification":"PTCB"},
  {"id":"ptcb-1319","stem":"What is the generic name for Vyvanse?","options":["Amphetamine salts","Methylphenidate","Lisdexamfetamine","Dextroamphetamine"],"correctIndex":2,"rationale":"Lisdexamfetamine is Vyvanse, a Schedule II prodrug stimulant for ADHD and binge eating disorder. It is converted to dextroamphetamine in the body. Mixed amphetamine salts is Adderall, methylphenidate is Ritalin/Concerta, dextroamphetamine is Dexedrine.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1320","stem":"A patient on metformin is scheduled for a CT scan with IV contrast dye. What should happen?","options":["Continue metformin as normal","Hold metformin for 48 hours after the procedure","Double the metformin dose before the procedure","Switch to insulin permanently"],"correctIndex":1,"rationale":"Metformin should be held for 48 hours after IV contrast administration due to risk of contrast-induced nephropathy and subsequent lactic acidosis. Renal function should be confirmed normal before restarting. This is a critical safety protocol.","difficulty":3,"category":"Drug Interactions","topic":"contrast-drug interactions","certification":"PTCB"},
  {"id":"ptcb-1321","stem":"What is the purpose of a 'first air' in sterile compounding?","options":["The first breath taken in the cleanroom","HEPA-filtered air that first contacts the critical site","Air from the ante room entering the buffer room","The initial airflow when the hood is turned on"],"correctIndex":1,"rationale":"First air refers to the HEPA-filtered air that contacts the critical site (needle tip, vial septum, syringe tip) before contacting any other object. Nothing should be placed between the HEPA filter and the critical site to avoid contamination.","difficulty":2,"category":"Sterile Products","topic":"aseptic technique","certification":"PTCB"},
  {"id":"ptcb-1322","stem":"What is the brand name for dexmethylphenidate?","options":["Concerta","Focalin","Vyvanse","Adderall"],"correctIndex":1,"rationale":"Focalin (and Focalin XR) is the brand name for dexmethylphenidate, a Schedule II CNS stimulant used for ADHD. It is the d-enantiomer of methylphenidate. Concerta is methylphenidate ER, Vyvanse is lisdexamfetamine, Adderall is amphetamine salts.","difficulty":2,"category":"Pharmacology","topic":"CNS stimulants","certification":"PTCB"},
  {"id":"ptcb-1323","stem":"A patient is taking phenytoin 300 mg daily. Phenytoin level returns at 25 mcg/mL (therapeutic: 10-20 mcg/mL). What should the technician do?","options":["Tell the patient to skip a dose","Notify the pharmacist of the elevated level","Increase the dose to achieve better seizure control","Dispense the refill without concern"],"correctIndex":1,"rationale":"Phenytoin at 25 mcg/mL is above the therapeutic range (10-20 mcg/mL), indicating toxicity risk. The technician should immediately notify the pharmacist. Symptoms of phenytoin toxicity include nystagmus, ataxia, and confusion. The technician should never adjust doses.","difficulty":2,"category":"Medication Safety","topic":"therapeutic drug monitoring","certification":"PTCB"},
  {"id":"ptcb-1324","stem":"How many ounces are in 1 cup?","options":["4 oz","6 oz","8 oz","12 oz"],"correctIndex":2,"rationale":"1 cup = 8 fluid ounces = 240 mL. This household measurement conversion is important for patient counseling and prescription interpretation. 1 oz ≈ 30 mL.","difficulty":1,"category":"Dosage Calculations","topic":"household conversions","certification":"PTCB"},
  {"id":"ptcb-1325","stem":"The sig code 'i-ii tabs PO q4-6h PRN pain' means:","options":["Take 1-2 tablets by mouth every 4-6 hours as needed for pain","Take 1 tablet by mouth 4-6 times daily","Take 2 tablets by mouth every 46 hours for pain","Inject 1-2 doses every 4-6 hours"],"correctIndex":0,"rationale":"Breaking down the sig: 'i-ii' = 1 to 2, 'tabs' = tablets, 'PO' = by mouth, 'q4-6h' = every 4 to 6 hours, 'PRN' = as needed, 'pain' = indication. The patient takes 1-2 tablets orally every 4-6 hours when they have pain.","difficulty":1,"category":"Prescription Processing","topic":"sig codes","certification":"PTCB"},
  {"id":"ptcb-1326","stem":"What is the brand name for liraglutide?","options":["Ozempic","Victoza","Trulicity","Mounjaro"],"correctIndex":1,"rationale":"Victoza is the brand name for liraglutide, a GLP-1 receptor agonist used for type 2 diabetes. Saxenda is also liraglutide but at a higher dose for weight management. Ozempic is semaglutide, Trulicity is dulaglutide, Mounjaro is tirzepatide.","difficulty":2,"category":"Pharmacology","topic":"diabetes medications","certification":"PTCB"},
  {"id":"ptcb-1327","stem":"According to OSHA, which type of personal protective equipment is required when handling hazardous drugs?","options":["Regular latex gloves only","Chemotherapy-rated gloves, gown, and eye protection","Standard surgical mask only","No PPE needed for oral hazardous drugs"],"correctIndex":1,"rationale":"OSHA and USP <800> require chemotherapy-rated (ASTM-tested) gloves, a protective gown, and eye/face protection when handling hazardous drugs. Double gloving is recommended. This applies to both sterile and non-sterile hazardous drug preparation.","difficulty":2,"category":"Sterile Products","topic":"hazardous drug handling","certification":"PTCB"},
  {"id":"ptcb-1328","stem":"What is the brand name for sitagliptin?","options":["Januvia","Tradjenta","Onglyza","Nesina"],"correctIndex":0,"rationale":"Sitagliptin is marketed as Januvia, a DPP-4 inhibitor for type 2 diabetes. Tradjenta is linagliptin, Onglyza is saxagliptin, and Nesina is alogliptin. DPP-4 inhibitors end in -gliptin.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1329","stem":"If 250 mL of a 50% dextrose solution is diluted to 1000 mL, what is the final concentration?","options":["5%","10%","12.5%","25%"],"correctIndex":2,"rationale":"Using C1V1 = C2V2: 50% × 250 mL = C2 × 1000 mL. C2 = 12,500 ÷ 1000 = 12.5%. The final concentration is 12.5% dextrose.","difficulty":2,"category":"Dosage Calculations","topic":"dilution calculations","certification":"PTCB"},
  {"id":"ptcb-1330","stem":"A technician accidentally dispenses the wrong medication to a patient. After the error is discovered, what should happen first?","options":["Destroy all evidence of the error","Notify the pharmacist and document an incident report","Call the patient's prescriber to change the medication","Refund the patient's copay and say nothing"],"correctIndex":1,"rationale":"After a dispensing error, the first step is to notify the pharmacist immediately, then document the error in an incident/occurrence report. The patient should be contacted to return the wrong medication. Error concealment is unethical and potentially illegal.","difficulty":1,"category":"Medication Safety","topic":"error reporting","certification":"PTCB"},
  {"id":"ptcb-1331","stem":"What is the generic name for Descovy?","options":["Tenofovir alafenamide/emtricitabine","Tenofovir disoproxil/emtricitabine","Abacavir/lamivudine","Dolutegravir/rilpivirine"],"correctIndex":0,"rationale":"Descovy contains emtricitabine/tenofovir alafenamide (TAF), used for HIV treatment and PrEP. Truvada contains emtricitabine/tenofovir disoproxil fumarate (TDF). TAF has less renal and bone toxicity than TDF.","difficulty":3,"category":"Pharmacology","topic":"antiretroviral medications","certification":"PTCB"},
  {"id":"ptcb-1332","stem":"A 10 mL vial of insulin contains 100 units/mL. If a patient uses 40 units daily, how many days will the vial last?","options":["10 days","20 days","25 days","28 days"],"correctIndex":2,"rationale":"Total units: 100 units/mL × 10 mL = 1000 units. Days = 1000 ÷ 40 = 25 days. However, opened insulin vials are typically only good for 28-30 days, so the vial would be used up before it expires.","difficulty":1,"category":"Dosage Calculations","topic":"insulin calculations","certification":"PTCB"},
  {"id":"ptcb-1333","stem":"Which vaccine must be stored frozen at -50°C or colder?","options":["Influenza vaccine","mRNA COVID-19 vaccine (original formulation)","Tetanus toxoid","Hepatitis B vaccine"],"correctIndex":1,"rationale":"The original Pfizer-BioNTech mRNA COVID-19 vaccine required ultra-cold storage at -60°C to -80°C. Newer formulations have less stringent requirements. Most other vaccines require refrigeration (2-8°C). Proper cold chain management prevents vaccine degradation.","difficulty":3,"category":"Inventory Management","topic":"vaccine storage","certification":"PTCB"},
  {"id":"ptcb-1334","stem":"What does the abbreviation DAW mean on a prescription?","options":["Dispense another way","Dispense as written","Drug approved for withdrawal","Discontinue after weighing"],"correctIndex":1,"rationale":"DAW stands for Dispense As Written, meaning the pharmacist must dispense the specific brand-name product the prescriber indicated. DAW codes range from 0 (no product selection indicated) to 9, controlling generic substitution.","difficulty":1,"category":"Prescription Processing","topic":"prescription abbreviations","certification":"PTCB"},
  {"id":"ptcb-1335","stem":"What is the brand name for trazodone?","options":["Desyrel","Elavil","Remeron","Pamelor"],"correctIndex":0,"rationale":"Trazodone is marketed as Desyrel, a serotonin antagonist and reuptake inhibitor (SARI) used for depression and commonly prescribed off-label for insomnia. Elavil is amitriptyline (TCA), Remeron is mirtazapine, Pamelor is nortriptyline (TCA).","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1336","stem":"If a pharmacy dispenses 120 prescriptions per day and has a 0.5% error rate, how many errors occur per month (30 days)?","options":["6 errors","12 errors","18 errors","24 errors"],"correctIndex":2,"rationale":"Daily errors: 120 × 0.005 = 0.6 errors/day. Monthly: 0.6 × 30 = 18 errors per month. Even a seemingly low error rate produces significant numbers over time, highlighting the importance of quality assurance.","difficulty":3,"category":"Dosage Calculations","topic":"quality metrics","certification":"PTCB"},
  {"id":"ptcb-1337","stem":"Which medication requires monitoring of absolute neutrophil count (ANC) and is dispensed through the Clozapine REMS program?","options":["Olanzapine","Quetiapine","Clozapine","Risperidone"],"correctIndex":2,"rationale":"Clozapine (Clozaril) requires ANC monitoring due to risk of severe neutropenia/agranulocytosis. The Clozapine REMS program mandates regular blood draws before dispensing. ANC must be ≥1500/μL (≥1000/μL for benign ethnic neutropenia) to continue therapy.","difficulty":3,"category":"Medication Safety","topic":"REMS programs","certification":"PTCB"},
  {"id":"ptcb-1338","stem":"A prescription calls for 'Amoxicillin 400 mg/5 mL, Disp: 100 mL, Sig: 1 tsp PO BID.' What is the day supply?","options":["5 days","10 days","14 days","20 days"],"correctIndex":1,"rationale":"1 tsp = 5 mL. BID = 2 times/day. Daily use: 5 mL × 2 = 10 mL/day. Day supply: 100 mL ÷ 10 mL/day = 10 days.","difficulty":1,"category":"Dosage Calculations","topic":"day supply calculations","certification":"PTCB"},
  {"id":"ptcb-1339","stem":"Which auxiliary label should accompany a tetracycline prescription?","options":["Take with dairy products","Avoid prolonged sun exposure","Refrigerate after opening","Shake well before use"],"correctIndex":1,"rationale":"Tetracyclines cause photosensitivity, making patients susceptible to severe sunburns. An 'Avoid sun/UV light' or 'May cause sensitivity to sunlight' auxiliary label is required. Tetracyclines should also avoid dairy/calcium (decreases absorption).","difficulty":2,"category":"Pharmacology","topic":"auxiliary labels","certification":"PTCB"},
  {"id":"ptcb-1340","stem":"What is the beyond-use date for opened multi-dose vials in most facilities?","options":["24 hours","48 hours","28 days","90 days"],"correctIndex":2,"rationale":"Per USP <797>, multi-dose vials may be used for up to 28 days after initial puncture, unless otherwise specified by the manufacturer. They must be stored properly and discarded if contamination is suspected or the beyond-use date is reached.","difficulty":2,"category":"Sterile Products","topic":"beyond-use dating","certification":"PTCB"},
  {"id":"ptcb-1341","stem":"What is the generic name for Toujeo?","options":["Insulin lispro","Insulin glargine","Insulin detemir","Insulin degludec"],"correctIndex":1,"rationale":"Toujeo contains insulin glargine U-300 (concentrated), a long-acting basal insulin. Lantus is also insulin glargine but U-100. Insulin lispro is Humalog, insulin detemir is Levemir, and insulin degludec is Tresiba.","difficulty":2,"category":"Pharmacology","topic":"insulin products","certification":"PTCB"},
  {"id":"ptcb-1342","stem":"A medication order reads 'Heparin 5000 units SubQ q8h.' The available vial is 10,000 units/mL. What volume should be drawn up?","options":["0.25 mL","0.5 mL","1 mL","2 mL"],"correctIndex":1,"rationale":"Volume = Desired dose ÷ Concentration = 5000 units ÷ 10,000 units/mL = 0.5 mL. Heparin is a high-alert medication; dose verification is critical to prevent life-threatening bleeding or clotting.","difficulty":2,"category":"Dosage Calculations","topic":"injectable calculations","certification":"PTCB"},
  {"id":"ptcb-1343","stem":"Under OSHA regulations, what type of eye wash station must be available where corrosive chemicals are handled?","options":["A bottle of sterile saline","A plumbed eye wash station capable of flushing both eyes for 15 minutes","Any container of clean water","Chemical-specific neutralizing solution"],"correctIndex":1,"rationale":"OSHA requires plumbed eye wash stations that can deliver a continuous 15-minute flush when corrosive chemicals are handled. Squeeze bottles are supplemental but do not meet the primary OSHA requirement for corrosive hazards.","difficulty":2,"category":"Medication Safety","topic":"workplace safety","certification":"PTCB"},
  {"id":"ptcb-1344","stem":"What is the brand name for paliperidone?","options":["Risperdal","Invega","Latuda","Vraylar"],"correctIndex":1,"rationale":"Invega is the brand name for paliperidone, an atypical antipsychotic (active metabolite of risperidone) used for schizophrenia. Available as oral (Invega) and long-acting injectable (Invega Sustenna/Trinza). Risperdal is risperidone, Latuda is lurasidone.","difficulty":2,"category":"Pharmacology","topic":"antipsychotic medications","certification":"PTCB"},
  {"id":"ptcb-1345","stem":"A pharmacy receives 50 mg/mL gentamicin vials. A patient needs 120 mg. How many mL should be drawn?","options":["1.2 mL","2.4 mL","6 mL","12 mL"],"correctIndex":1,"rationale":"Volume = Dose ÷ Concentration = 120 mg ÷ 50 mg/mL = 2.4 mL. Aminoglycosides like gentamicin require precise dosing and therapeutic drug monitoring due to nephrotoxicity and ototoxicity risks.","difficulty":2,"category":"Dosage Calculations","topic":"injectable calculations","certification":"PTCB"},
  {"id":"ptcb-1346","stem":"What is the purpose of a medication therapy management (MTM) service?","options":["To reduce pharmacy inventory costs","To optimize therapeutic outcomes through comprehensive medication review","To replace physician consultations","To process insurance claims faster"],"correctIndex":1,"rationale":"MTM is a patient-centered service that optimizes therapeutic outcomes through comprehensive medication review, identifying drug-related problems, creating medication action plans, and providing education. Pharmacists lead MTM services, often for patients with multiple chronic conditions.","difficulty":2,"category":"Prescription Processing","topic":"pharmacy services","certification":"PTCB"},
  {"id":"ptcb-1347","stem":"What is the generic name for Stelara?","options":["Adalimumab","Ustekinumab","Secukinumab","Certolizumab"],"correctIndex":1,"rationale":"Ustekinumab is the generic name for Stelara, a biologic that targets IL-12 and IL-23. Used for plaque psoriasis, psoriatic arthritis, and Crohn disease. Adalimumab is Humira (TNF inhibitor), secukinumab is Cosentyx (IL-17), certolizumab is Cimzia (TNF).","difficulty":3,"category":"Pharmacology","topic":"biologic medications","certification":"PTCB"},
  {"id":"ptcb-1348","stem":"When performing aseptic technique, how far inside the laminar airflow hood should you work?","options":["At the very edge","At least 3 inches","At least 6 inches","At least 12 inches"],"correctIndex":2,"rationale":"You must work at least 6 inches inside the LAFW to stay within the zone of unidirectional HEPA-filtered air. Working too close to the edge risks contamination from room air. Large objects should be placed to the side, not between the HEPA filter and the work.","difficulty":1,"category":"Sterile Products","topic":"aseptic technique","certification":"PTCB"},
  {"id":"ptcb-1349","stem":"A patient needs 7.5 mg of warfarin daily. Available tablets are 5 mg and 2.5 mg. What combination provides the correct dose?","options":["One and a half 5 mg tablets","One 5 mg tablet and one 2.5 mg tablet","Three 2.5 mg tablets","Two 5 mg tablets"],"correctIndex":1,"rationale":"One 5 mg tablet (5 mg) + one 2.5 mg tablet (2.5 mg) = 7.5 mg total. This is preferred over breaking tablets when multiple strengths are available, as it ensures dose accuracy for this narrow therapeutic index drug.","difficulty":1,"category":"Dosage Calculations","topic":"tablet calculations","certification":"PTCB"},
  {"id":"ptcb-1350","stem":"What is the primary difference between USP <795> and USP <797>?","options":["<795> covers sterile compounding and <797> covers non-sterile","<795> covers non-sterile compounding and <797> covers sterile compounding","Both cover sterile compounding for different settings","<795> is for retail and <797> is for hospital only"],"correctIndex":1,"rationale":"USP <795> establishes standards for non-sterile compounding (capsules, creams, ointments), while USP <797> covers sterile compounding (IV preparations, ophthalmic solutions). USP <800> specifically addresses hazardous drug handling.","difficulty":2,"category":"Compounding","topic":"USP standards","certification":"PTCB"},
  {"id":"ptcb-1351","stem":"What does the acronym ADME stand for in pharmacokinetics?","options":["Administration, Dispensing, Metabolism, Excretion","Absorption, Distribution, Metabolism, Excretion","Analysis, Detection, Monitoring, Evaluation","Absorption, Dosing, Monitoring, Elimination"],"correctIndex":1,"rationale":"ADME stands for Absorption, Distribution, Metabolism, and Excretion — the four key pharmacokinetic processes that determine drug concentration in the body. Understanding ADME helps predict drug interactions and dosing adjustments.","difficulty":1,"category":"Pharmacology","topic":"pharmacokinetics","certification":"PTCB"},
  {"id":"ptcb-1352","stem":"How many mL is equivalent to 1 fluid ounce?","options":["5 mL","15 mL","30 mL","60 mL"],"correctIndex":2,"rationale":"1 fluid ounce = approximately 30 mL (29.57 mL exactly). This is a commonly tested conversion. 1 pint = 473 mL, 1 gallon = 3785 mL.","difficulty":1,"category":"Dosage Calculations","topic":"household conversions","certification":"PTCB"},
  {"id":"ptcb-1353","stem":"Which of the following drugs is classified as a Schedule IV controlled substance?","options":["Oxycodone","Codeine with APAP","Zolpidem","Pregabalin"],"correctIndex":2,"rationale":"Zolpidem (Ambien) is a Schedule IV controlled substance. Oxycodone is C-II, codeine with APAP is C-III, and pregabalin (Lyrica) is C-V. C-IV drugs have lower abuse potential than C-II and C-III.","difficulty":2,"category":"Regulations/Law","topic":"DEA schedules","certification":"PTCB"},
  {"id":"ptcb-1354","stem":"What is the generic name for Ozempic pen?","options":["Liraglutide","Semaglutide","Dulaglutide","Tirzepatide"],"correctIndex":1,"rationale":"Semaglutide is the generic for Ozempic (for type 2 diabetes) and Wegovy (for weight management). It is a once-weekly injectable GLP-1 receptor agonist. An oral form (Rybelsus) is also available.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1355","stem":"A compounding pharmacy needs to prepare 200 g of a 5% salicylic acid ointment. How many grams of salicylic acid are needed?","options":["5 g","10 g","15 g","20 g"],"correctIndex":1,"rationale":"5% means 5 g per 100 g. For 200 g: (5/100) × 200 = 10 g of salicylic acid. The remaining 190 g would be the ointment base. This is a basic percent strength calculation for compounding.","difficulty":2,"category":"Compounding","topic":"percentage calculations","certification":"PTCB"},
  {"id":"ptcb-1356","stem":"Which anticoagulant can be reversed with protamine sulfate?","options":["Warfarin","Heparin","Apixaban","Dabigatran"],"correctIndex":1,"rationale":"Protamine sulfate reverses heparin (both unfractionated and partially reverses LMWH like enoxaparin). Warfarin is reversed with vitamin K and FFP/PCC. Apixaban (Xa inhibitor) is reversed with andexanet alfa. Dabigatran is reversed with idarucizumab (Praxbind).","difficulty":3,"category":"Drug Interactions","topic":"antidote reversal agents","certification":"PTCB"},
  {"id":"ptcb-1357","stem":"What is the brand name for vilazodone?","options":["Trintellix","Viibryd","Brintellix","Fetzima"],"correctIndex":1,"rationale":"Viibryd is the brand name for vilazodone, an SSRI with partial 5-HT1A agonism used for major depressive disorder. Trintellix is vortioxetine, and Fetzima is levomilnacipran (SNRI). Should be taken with food for optimal absorption.","difficulty":2,"category":"Pharmacology","topic":"antidepressant medications","certification":"PTCB"},
  {"id":"ptcb-1358","stem":"A patient is prescribed enoxaparin 1 mg/kg SubQ BID. The patient weighs 75 kg. The available prefilled syringe is 150 mg/mL. What volume per dose?","options":["0.25 mL","0.5 mL","0.75 mL","1 mL"],"correctIndex":1,"rationale":"Dose: 1 mg/kg × 75 kg = 75 mg per dose. Volume: 75 mg ÷ 150 mg/mL = 0.5 mL. Enoxaparin (Lovenox) is a low-molecular-weight heparin that does not require routine monitoring like unfractionated heparin.","difficulty":2,"category":"Dosage Calculations","topic":"weight-based dosing","certification":"PTCB"},
  {"id":"ptcb-1359","stem":"Which of the following is an example of a medication error caused by 'trailing zero' use?","options":["Writing 1.0 mg instead of 1 mg, misread as 10 mg","Writing mg instead of mcg","Using 'U' for units","Abbreviating medication names"],"correctIndex":0,"rationale":"A trailing zero (1.0 mg) can be misread as 10 mg — a 10-fold overdose. ISMP and The Joint Commission prohibit trailing zeros. A leading zero IS required (0.5 mg, not .5 mg) to prevent misreading as 5 mg.","difficulty":2,"category":"Medication Safety","topic":"error-prone practices","certification":"PTCB"},
  {"id":"ptcb-1360","stem":"What is the generic name for Breztri Aerosphere?","options":["Budesonide/glycopyrrolate/formoterol","Fluticasone/umeclidinium/vilanterol","Beclomethasone/aclidinium/formoterol","Mometasone/glycopyrrolate/indacaterol"],"correctIndex":0,"rationale":"Breztri Aerosphere contains budesonide/glycopyrrolate/formoterol fumarate, another ICS/LAMA/LABA triple therapy for COPD. Unlike Trelegy Ellipta (dry powder), Breztri is a metered-dose inhaler (MDI).","difficulty":3,"category":"Pharmacology","topic":"respiratory medications","certification":"PTCB"},
  {"id":"ptcb-1361","stem":"What is the total parenteral nutrition (TPN) component that provides the primary calorie source?","options":["Amino acids","Dextrose","Lipids","Electrolytes"],"correctIndex":1,"rationale":"Dextrose is the primary calorie source in TPN, providing 3.4 kcal/g. Amino acids (4 kcal/g) provide protein. Lipids (9-10 kcal/g) provide essential fatty acids and additional calories. Electrolytes and trace elements do not provide calories.","difficulty":3,"category":"Sterile Products","topic":"parenteral nutrition","certification":"PTCB"},
  {"id":"ptcb-1362","stem":"A prescription reads: 'Amoxicillin 875 mg, #20, Sig: i tab PO BID.' The patient has a penicillin allergy documented. What should the technician do?","options":["Fill the prescription as written","Alert the pharmacist about the allergy","Tell the patient to take the medication with food to avoid reactions","Switch to azithromycin"],"correctIndex":1,"rationale":"Amoxicillin is a penicillin-class antibiotic. A documented penicillin allergy is a critical contraindication. The technician must alert the pharmacist before dispensing. The technician should never substitute medications or give medical advice.","difficulty":1,"category":"Medication Safety","topic":"allergy screening","certification":"PTCB"},
  {"id":"ptcb-1363","stem":"Which law established the distinction between prescription (legend) and over-the-counter medications?","options":["Controlled Substances Act","Durham-Humphrey Amendment","Kefauver-Harris Amendment","Federal Food, Drug, and Cosmetic Act"],"correctIndex":1,"rationale":"The Durham-Humphrey Amendment (1951) established two categories of drugs: prescription (legend) drugs requiring a prescriber's authorization, and OTC drugs that are safe for self-medication. Legend drugs must bear the statement 'Rx Only.'","difficulty":2,"category":"Regulations/Law","topic":"pharmacy law history","certification":"PTCB"},
  {"id":"ptcb-1364","stem":"What is the brand name for brexpiprazole?","options":["Abilify","Vraylar","Rexulti","Latuda"],"correctIndex":2,"rationale":"Rexulti is the brand name for brexpiprazole, an atypical antipsychotic used as adjunctive therapy for major depressive disorder and for schizophrenia. Abilify is aripiprazole, Vraylar is cariprazine, and Latuda is lurasidone.","difficulty":2,"category":"Pharmacology","topic":"antipsychotic medications","certification":"PTCB"},
  {"id":"ptcb-1365","stem":"Calculate the quantity of 70% isopropyl alcohol and 30% isopropyl alcohol needed to prepare 1 liter of 50% isopropyl alcohol using alligation.","options":["500 mL of each","250 mL of 70% and 750 mL of 30%","750 mL of 70% and 250 mL of 30%","600 mL of 70% and 400 mL of 30%"],"correctIndex":0,"rationale":"Alligation: 70% gives (50-30) = 20 parts. 30% gives (70-50) = 20 parts. Total = 40 parts. 70% needed: (20/40) × 1000 = 500 mL. 30% needed: (20/40) × 1000 = 500 mL. Equal parts because the desired concentration is exactly midway.","difficulty":3,"category":"Dosage Calculations","topic":"alligation","certification":"PTCB"},
  {"id":"ptcb-1366","stem":"What is the generic name for Wegovy?","options":["Liraglutide","Semaglutide","Tirzepatide","Dulaglutide"],"correctIndex":1,"rationale":"Wegovy contains semaglutide at a higher dose, approved for chronic weight management. Ozempic is also semaglutide but for type 2 diabetes. Liraglutide has Saxenda (weight) and Victoza (diabetes) versions. Tirzepatide is Mounjaro/Zepbound.","difficulty":2,"category":"Pharmacology","topic":"weight management medications","certification":"PTCB"},
  {"id":"ptcb-1367","stem":"A technician notices that two different patients' prescriptions were placed in the same bag. What type of error could this cause?","options":["Wrong dose error","Wrong drug error","Wrong patient error","Wrong route error"],"correctIndex":2,"rationale":"Placing multiple patients' prescriptions in one bag can lead to a wrong patient error — one of the most common and preventable dispensing errors. The final verification step should include matching the bag label to the patient and all enclosed prescriptions.","difficulty":1,"category":"Medication Safety","topic":"dispensing errors","certification":"PTCB"},
  {"id":"ptcb-1368","stem":"What is the volume of a standard insulin syringe used for U-100 insulin?","options":["0.3 mL, 0.5 mL, or 1 mL","2 mL or 3 mL","5 mL or 10 mL","20 mL"],"correctIndex":0,"rationale":"Standard U-100 insulin syringes come in 0.3 mL (30 units), 0.5 mL (50 units), and 1 mL (100 units) sizes. The syringe size should match the dose to improve accuracy. U-100 means 100 units per mL. Using the wrong syringe with wrong insulin can cause fatal dosing errors.","difficulty":1,"category":"Dosage Calculations","topic":"insulin syringes","certification":"PTCB"},
  {"id":"ptcb-1369","stem":"Which agency is responsible for approving new drugs in the United States?","options":["DEA","CDC","FDA","CMS"],"correctIndex":2,"rationale":"The FDA (Food and Drug Administration) is responsible for approving new drugs through the NDA (New Drug Application) process. The DEA regulates controlled substances, the CDC handles disease prevention, and CMS administers Medicare/Medicaid.","difficulty":1,"category":"Regulations/Law","topic":"regulatory agencies","certification":"PTCB"},
  {"id":"ptcb-1370","stem":"What is the brand name for spironolactone?","options":["Lasix","Bumex","Aldactone","Microzide"],"correctIndex":2,"rationale":"Spironolactone is marketed as Aldactone, a potassium-sparing diuretic and aldosterone antagonist used for heart failure, hypertension, and hyperaldosterism. Lasix is furosemide, Bumex is bumetanide (both loop diuretics), Microzide is HCTZ (thiazide).","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1371","stem":"How should nitroglycerin sublingual tablets be stored?","options":["In a plastic bag at room temperature","In the original glass container, tightly closed, away from heat and moisture","In the refrigerator","In a weekly pill organizer"],"correctIndex":1,"rationale":"Nitroglycerin SL tablets must be stored in the original amber glass container, tightly closed, to protect from light, heat, moisture, and plastic (which absorbs the drug). They should be replaced every 6 months after opening.","difficulty":2,"category":"Inventory Management","topic":"special storage requirements","certification":"PTCB"},
  {"id":"ptcb-1372","stem":"A prescription is written for 'Augmentin 500/125 mg.' What do the two numbers represent?","options":["Amoxicillin 500 mg / Clavulanate 125 mg","Two different tablet strengths","Loading dose / Maintenance dose","Morning dose / Evening dose"],"correctIndex":0,"rationale":"Augmentin contains two active ingredients: amoxicillin (the antibiotic) and clavulanic acid/clavulanate (a beta-lactamase inhibitor). The 500/125 notation means 500 mg amoxicillin plus 125 mg clavulanate per tablet.","difficulty":1,"category":"Prescription Processing","topic":"combination drugs","certification":"PTCB"},
  {"id":"ptcb-1373","stem":"What is the generic name for Zepbound?","options":["Semaglutide","Tirzepatide","Liraglutide","Dulaglutide"],"correctIndex":1,"rationale":"Tirzepatide is the generic for Zepbound (chronic weight management) and Mounjaro (type 2 diabetes). It is a dual GIP/GLP-1 receptor agonist. Semaglutide is Wegovy/Ozempic, liraglutide is Saxenda/Victoza, dulaglutide is Trulicity.","difficulty":2,"category":"Pharmacology","topic":"weight management medications","certification":"PTCB"},
  {"id":"ptcb-1374","stem":"A compounding pharmacy prepares 60 capsules. Quality check shows the total weight should be 18 g ± 5%. What is the acceptable weight range?","options":["17.1 g to 18.9 g","16.2 g to 19.8 g","15.3 g to 20.7 g","17.55 g to 18.45 g"],"correctIndex":0,"rationale":"5% of 18 g = 0.9 g. Acceptable range: 18 - 0.9 = 17.1 g to 18 + 0.9 = 18.9 g. Quality control weight checks ensure uniformity and accuracy of compounded preparations.","difficulty":2,"category":"Compounding","topic":"quality control","certification":"PTCB"},
  {"id":"ptcb-1375","stem":"Which drug interaction can cause potentially fatal hyperkalemia?","options":["ACE inhibitor + potassium supplement","Statin + fibrate","PPI + H2 blocker","SSRI + benzodiazepine"],"correctIndex":0,"rationale":"ACE inhibitors reduce aldosterone, decreasing potassium excretion. Adding potassium supplements can cause dangerous hyperkalemia (K+ >5.5 mEq/L), leading to cardiac arrhythmias. Potassium levels must be monitored closely. Spironolactone + ACE inhibitor also increases this risk.","difficulty":2,"category":"Drug Interactions","topic":"electrolyte interactions","certification":"PTCB"},
  {"id":"ptcb-1376","stem":"What is the brand name for tirzepatide?","options":["Ozempic","Trulicity","Mounjaro","Victoza"],"correctIndex":2,"rationale":"Tirzepatide is marketed as Mounjaro for type 2 diabetes and Zepbound for weight management. It is a dual GIP/GLP-1 receptor agonist. Ozempic is semaglutide, Trulicity is dulaglutide, Victoza is liraglutide.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1377","stem":"What is the proper procedure when a pharmacy technician discovers a medication has been recalled?","options":["Continue dispensing until current stock is depleted","Quarantine the affected products, notify the pharmacist, and check dispensing records","Return the products to the shelf after relabeling","Discard the products in regular trash"],"correctIndex":1,"rationale":"When a recall is identified, the technician should immediately quarantine (remove from dispensing stock) all affected products, notify the pharmacist, and check dispensing records to identify patients who may have received the recalled medication. Products are returned per the recall procedure.","difficulty":1,"category":"Inventory Management","topic":"recall procedures","certification":"PTCB"},
  {"id":"ptcb-1378","stem":"How many mcg are in 1 mg?","options":["10 mcg","100 mcg","1,000 mcg","10,000 mcg"],"correctIndex":2,"rationale":"1 mg = 1,000 mcg (micrograms). This metric conversion is critical for medications like levothyroxine (measured in mcg), fentanyl patches (mcg/hr), and insulin (measured in units). Confusing mg and mcg can cause 1000-fold dosing errors.","difficulty":1,"category":"Dosage Calculations","topic":"metric conversions","certification":"PTCB"},
  {"id":"ptcb-1379","stem":"What is the generic name for Caplyta?","options":["Pimozide","Lumateperone","Cariprazine","Iloperidone"],"correctIndex":1,"rationale":"Lumateperone is the generic name for Caplyta, an atypical antipsychotic used for schizophrenia and bipolar depression. It has a unique mechanism affecting serotonin, dopamine, and glutamate. Pimozide is Orap, cariprazine is Vraylar, iloperidone is Fanapt.","difficulty":3,"category":"Pharmacology","topic":"antipsychotic medications","certification":"PTCB"},
  {"id":"ptcb-1380","stem":"A patient is taking amlodipine 10 mg for hypertension. They report significant ankle swelling. What type of adverse effect is this?","options":["Allergic reaction requiring epinephrine","Common side effect of calcium channel blockers (peripheral edema)","Drug interaction with another medication","Sign of heart failure requiring hospitalization"],"correctIndex":1,"rationale":"Peripheral edema (ankle swelling) is a common dose-dependent side effect of dihydropyridine CCBs like amlodipine. It results from precapillary vasodilation, not fluid retention. The technician should document and refer the patient to the pharmacist for counseling.","difficulty":2,"category":"Drug Interactions","topic":"adverse effect recognition","certification":"PTCB"},
  {"id":"ptcb-1381","stem":"Which medication should be protected from light and dispensed in an amber container?","options":["Amoxicillin capsules","Nitroglycerin sublingual tablets","Metformin tablets","Lisinopril tablets"],"correctIndex":1,"rationale":"Nitroglycerin SL tablets are light-sensitive and must be dispensed in amber glass containers. Other light-sensitive drugs include methotrexate, furosemide, nifedipine, and some IV medications. Amber containers block UV light that can degrade the drug.","difficulty":1,"category":"Inventory Management","topic":"light-sensitive drugs","certification":"PTCB"},
  {"id":"ptcb-1382","stem":"What does the abbreviation 'UD' mean in a prescription sig?","options":["Under direction","As directed","Until discontinued","Unit dose"],"correctIndex":1,"rationale":"UD means 'ut dictum' (as directed). The prescriber's verbal instructions supplement the written prescription. The pharmacist should clarify specific directions with the prescriber before dispensing to ensure patient understanding.","difficulty":2,"category":"Prescription Processing","topic":"sig codes","certification":"PTCB"},
  {"id":"ptcb-1383","stem":"What is the brand name for empagliflozin?","options":["Invokana","Farxiga","Jardiance","Steglatro"],"correctIndex":2,"rationale":"Empagliflozin is marketed as Jardiance, an SGLT2 inhibitor for type 2 diabetes and heart failure. It has demonstrated cardiovascular and renal benefits. Invokana is canagliflozin, Farxiga is dapagliflozin, Steglatro is ertugliflozin.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs","certification":"PTCB"},
  {"id":"ptcb-1384","stem":"A patient needs 0.25 mg of digoxin. Available tablets are 0.125 mg. How many tablets should be dispensed per dose?","options":["0.5 tablet","1 tablet","2 tablets","4 tablets"],"correctIndex":2,"rationale":"0.25 mg ÷ 0.125 mg/tablet = 2 tablets per dose. Digoxin has a narrow therapeutic index, so accurate dosing is critical. The pharmacist should verify this calculation.","difficulty":1,"category":"Dosage Calculations","topic":"tablet calculations","certification":"PTCB"},
  {"id":"ptcb-1385","stem":"Which immune checkpoint inhibitor drug suffix identifies monoclonal antibodies?","options":["-mab","-nib","-vir","-pril"],"correctIndex":0,"rationale":"The suffix -mab identifies monoclonal antibodies (adalimumab, pembrolizumab, trastuzumab). -nib identifies kinase inhibitors, -vir identifies antivirals, and -pril identifies ACE inhibitors. Knowing suffixes helps identify drug classes.","difficulty":2,"category":"Drug Classifications","topic":"drug suffixes","certification":"PTCB"}
];
